Here's a complete implementation:

```csharp
// In Program.cs

// Configure request size limit (before builder.Build())
builder.Services.Configure<Microsoft.AspNetCore.Http.Features.FormOptions>(options =>
{
    options.MultipartBodyLengthLimit = 10 * 1024 * 1024; // 10MB
});

// If using Kestrel directly:
builder.WebHost.ConfigureKestrel(options =>
{
    options.Limits.MaxRequestBodySize = 10 * 1024 * 1024;
});

// --- After app = builder.Build() ---

app.MapPost("/upload", async (IFormFile file) =>
{
    // Validate content type
    string[] allowedTypes = ["image/jpeg", "image/png"];
    if (!allowedTypes.Contains(file.ContentType))
    {
        return Results.BadRequest("Only JPEG and PNG files are allowed.");
    }

    // Validate size (defense in depth)
    const long maxSize = 10 * 1024 * 1024;
    if (file.Length > maxSize)
    {
        return Results.BadRequest("File size exceeds the 10MB limit.");
    }

    // Ensure uploads directory exists
    var uploadsPath = Path.Combine(Directory.GetCurrentDirectory(), "uploads");
    Directory.CreateDirectory(uploadsPath);

    // Generate safe filename
    var extension = Path.GetExtension(file.FileName).ToLowerInvariant();
    if (extension is not ".jpg" and not ".jpeg" and not ".png")
    {
        return Results.BadRequest("Invalid file extension.");
    }

    var fileName = $"{Guid.NewGuid()}{extension}";
    var filePath = Path.Combine(uploadsPath, fileName);

    // Save file
    await using var stream = new FileStream(filePath, FileMode.Create);
    await file.CopyToAsync(stream);

    return Results.Ok(new { fileName, size = file.Length });
})
.DisableAntiforgery(); // Required for API clients without antiforgery tokens
```

**Key points:**

- **`DisableAntiforgery()`** — since your pipeline has `UseAntiforgery()`, API endpoints accepting `IFormFile` need this unless you're sending the antiforgery token. Remove it if clients will provide the token.
- **Double validation** — both content type and extension are checked to prevent spoofing.
- **`Guid` filename** — avoids path traversal and collisions.
- **`FormOptions` + Kestrel limit** — both layers enforce the 10MB cap; without the Kestrel setting, large requests get rejected with a generic connection reset before your validation runs.

If you want to keep antiforgery protection, remove `.DisableAntiforgery()` and have clients send the token via the `RequestVerificationToken` header or form field.
